tb_status tb_rt_init(tb_rt *rt, const char *journal_path) {
  if (!rt || !journal_path)
    return TB_ERR_BAD_ARG;
  memset(rt, 0, sizeof(*rt));

  if (!tb_map_u64_init(&rt->token_to_id, 128))
    return TB_ERR_OOM;
  if (!tb_map_u64_init(&rt->token_done, 128))
