    uint64_t id64 = 0;
    if (!tb_map_u64_get(&rt->token_to_id, token, &id64))
      continue;
    tb_event ev = {.kind = TB_EV_POKE, .id = (uint32_t)id64};
    (void)tb_vec_ev_push(&rt->evlog, ev);
  }
  return TB_OK;
}
