tb_status tb_ingest_tick(tb_rt *rt, tb_profile prof, uint32_t tick, uint32_t *submitted_out) {
  if (!rt || !submitted_out)
    return TB_ERR_BAD_ARG;

  uint32_t n = tb_profile_should_submit(prof, tick);
  *submitted_out = n;

